commands.cmd:
out=$(timeout 20 docker system df --format '{{json .}}') || { echo "docker system df failed" >&2; exit 1; }
printf '%s' "$out" | jq -sc '
  map(select(.Type=="Images")) as $imgs
  | if ($imgs | length) == 0 then error("no Images row in docker system df") else
      $imgs[0] as $i
      | {
          reclaimable_pct: ($i.Reclaimable | (capture("\\((?<p>[0-9]+)%\\)") | .p | tonumber) // 0),
          size: $i.Size,
          reclaimable: $i.Reclaimable
        }
    end
' || { echo "jq failed" >&2; exit 1; }
